def calculate_loan_payback_period(principal, annual_interest_rate, monthly_payment):
    if monthly_payment <= 0:
        raise ValueError("Monthly payment must be greater than zero.")
    if principal <= 0:
        raise ValueError("Principal must be greater than zero.")
    if annual_interest_rate < 0:
        raise ValueError("Annual interest rate cannot be negative.")

    monthly_interest_rate = annual_interest_rate / 12 / 100
    total_months = 0
    remaining_balance = principal

    while remaining_balance > 0:
        interest_for_month = remaining_balance * monthly_interest_rate
        remaining_balance += interest_for_month - monthly_payment
        total_months += 1

        if total_months > 1000:  # Prevent infinite loop for unrealistic scenarios
            raise ValueError("Loan cannot be paid back in a realistic timeframe.")

    return total_months

def calculate_monthly_payment(principal, annual_interest_rate, total_months):
    if total_months <= 0:
        raise ValueError("Total months must be greater than zero.")
    if principal <= 0:
        raise ValueError("Principal must be greater than zero.")
    if annual_interest_rate < 0:
        raise ValueError("Annual interest rate cannot be negative.")

    monthly_interest_rate = annual_interest_rate / 12 / 100
    if monthly_interest_rate == 0:
        return principal / total_months

    monthly_payment = (principal * monthly_interest_rate) / (1 - (1 + monthly_interest_rate) ** -total_months)
    return monthly_payment

def solve(principal, annual_interest_rate, monthly_payment):
    total_months = calculate_loan_payback_period(principal, annual_interest_rate, monthly_payment)
    return total_months, calculate_monthly_payment(principal, annual_interest_rate, total_months)
